queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:EventTypeID ?cg . ?child a :Events ; p:EventTypeID ?cg . ?l p:FestivalID ?pg . ?parent a :Festivals ; p:FestivalID ?pg . } GROUP BY ?child }
  ?child p:Description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Festivals } }
  FILTER(?nf = ?total)
}

